local UILoopScroll = LxClass("UILoopScroll", nil)

function UILoopScroll:UILoopScroll()

end

function UILoopScroll:GetSeqCom()
    if not self._seqCom then
        self._seqCom = SequenceCom:New()
    end

    return self._seqCom
end

function UILoopScroll:Create(data)
    self._contentTran = data.contentTran
    self._viewLength = data.viewLength
    self._itemLength = data.itemLength
    self._objPool = data.objPool
    self._onItemDraw = data.onItemDraw
    self._dataList = data.dataList
    self._onItemCenter = data.onItemCenter
    self._isLoop = data.isLoop == nil and true or data.isLoop
    self._onPosChange = data.onPosChange

    local cnt = math.ceil(self._viewLength/self._itemLength)

    self._itemMap = {}
    self:SetPosIndex(1)
    for k=1,cnt do
        local obj = self._objPool:GetObj()
        local data =
        {
            obj = obj,
            posIndex = k,
        }

        self:InitDragCom(data)
        self._itemMap[k] = data
    end

    CS.SetOnBeginDrag(self._contentTran.gameObject,function (...) self:OnDragImageBegin(...) end)
    CS.SetOnDrag(self._contentTran.gameObject,function (...) self:OnDragImage(...) end)
    CS.SetOnEndDrag(self._contentTran.gameObject,function (...) self:OnDragImageEnd(...) end)

end

function UILoopScroll:OnDragImageBegin(go,eventData)
    self._beginPos = eventData.position
    self._contentPos = self._contentTran.anchoredPosition
end

function UILoopScroll:OnDragImage(go,eventData)
    local offset = eventData.position - self._beginPos
    local pos = self._contentPos + offset

    local dir = offset.x < 0 and 1 or 2
    if not self:CheckCanMove(dir) then
        return
    end

    self._contentTran.anchoredPosition = Vector2.New(pos.x,0)

    self:ModifyItemPos()
end

function UILoopScroll:OnDragImageEnd(go,eventData)
    local endPos = eventData.position
    local moveX = endPos.x - self._beginPos.x

    self:AdjustPosition(moveX)
end

function UILoopScroll:MoveLeft()
    self:SetPosIndex(self._posIndex + 1)
    self:StartMoveTween()
end

function UILoopScroll:MoveRight()
    self:SetPosIndex(self._posIndex - 1)
    self:StartMoveTween()
end

function UILoopScroll:MoveToIndex(index)
    local cnt = #self._dataList
    local actualIndex = self:GetDataIndex(self._posIndex)

    local offset = nil

    if self._isLoop then
        if index > actualIndex then
            local offsetL = index - actualIndex
            local offsetR = actualIndex + cnt - index
            if offsetL< offsetR then
                offset = - offsetL
            elseif offsetL == offsetR then
                offset = - offsetL
            else
                offset = offsetR
            end
        elseif index < actualIndex then
            local offsetL = index + cnt - actualIndex
            local offsetR = actualIndex - index
            if offsetL< offsetR then
                offset = -offsetL
            elseif offsetL == offsetR then
                offset = offsetR
            else
                offset = offsetR
            end
        else
            return
        end
    else
        if index > actualIndex then
            local offsetL = index - actualIndex
            offset = - offsetL
        elseif index < actualIndex then
            local offsetR = actualIndex - index
            offset = offsetR
        else
            return
        end
    end

    self:SetPosIndex(self._posIndex + offset)
    self:StartMoveTween()
end

function UILoopScroll:AdjustPosition(movex)
    local newPosIndex = self._posIndex
    if movex >50 then
        newPosIndex = newPosIndex + 1
    elseif movex < 50 then
        newPosIndex = newPosIndex - 1
    end

    self:SetPosIndex(newPosIndex)

    self:StartMoveTween()
end

function UILoopScroll:CheckCanMove(dir)
    if self._isLoop then
        return true
    end
    local cnt = #self._dataList
    local index = self:GetDataIndex(self._posIndex)
    if index ==0 then
        index = cnt
    end

    if index == cnt and dir == 1 then
        return false
    elseif index == 1 and dir == 2 then
        return false
    end

    return true

end

function UILoopScroll:SetPosIndex(newPosIndex)
    if not self._isLoop then
        local cnt = #self._dataList
        newPosIndex = Mathf.Clamp(newPosIndex,-cnt+2,1)
    end

    self._posIndex = newPosIndex

    self:OnPosIndexChange()
end

function UILoopScroll:StartMoveTween()
    local endPos = Vector2.New(self._itemLength * (self._posIndex - 1),0)

    local startPos = self._contentTran.anchoredPosition
    local seqCom = self:GetSeqCom()
    local seq = seqCom:CreateSeq("move")
    local tween = YXTween.TweenFloat(0,1,0.5,function (t)
        local pos = Vector2.Lerp(startPos,endPos,t)
        self._contentTran.anchoredPosition = pos
        self:ModifyItemPos()
        self:OnMoveEnd()
    end)
    seq:Append(tween)
    seq:PlayForward()
end

function UILoopScroll:ModifyItemPos()
    local viewLength = self._viewLength
    local itemLength = self._itemLength
    local posX = self._contentTran.anchoredPosition.x
    local viewRange = Vector2.New(-posX,-posX + viewLength)

    local removeKey = {}
    for k,v in pairs(self._itemMap) do
        local data = v
        local leftE = data.obj.anchoredPosition.x
        local rightE = leftE + itemLength

        local isIn = self:CheckItemInView(viewRange,Vector2.New(leftE,rightE))
        if not isIn then
            table.insert(removeKey,k)
        end
    end

    for k,v in ipairs(removeKey) do
        local data = self._itemMap[v]
        self._itemMap[v] = nil
        self._objPool:ReturnObj(data.obj)
    end

    local startPosIndex =math.floor(-posX/itemLength)
    local isEnter = false
    while true do
        startPosIndex = startPosIndex + 1
        local leftE = itemLength*(startPosIndex - 1)
        local rightE = leftE + itemLength
        local isIn = self:CheckItemInView(viewRange,Vector2.New(leftE,rightE))
        if isIn then
            isEnter = true
            local data = self._itemMap[startPosIndex]
            if not data then
                local obj = self._objPool:GetObj()
                data =
                {
                    obj = obj,
                    posIndex = startPosIndex,
                }
                self._itemMap[startPosIndex] = data
                self:InitDragCom(data)
            end



        else
            if isEnter then
                break
            end
        end

    end

end





function UILoopScroll:CheckItemInView(viewRange,itemRange)
    if itemRange.y < viewRange.x or itemRange.x > viewRange.y then
        return false
    end

    return true
end

function UILoopScroll:InitDragCom(data)
    local obj = data.obj
    CS.SetParentTrans(obj.transform,self._contentTran)
    local pos = Vector2.New(self._itemLength*(data.posIndex-1),0)
    obj.transform.anchoredPosition = pos

    if self._onItemDraw then
        local index = self:GetDataIndex(data.posIndex)
        obj.transform.name = string.format("item{%s}",index)
        self._onItemDraw(obj.transform,self._dataList[index])
    end
end

function UILoopScroll:OnMoveEnd()
    if self._onItemCenter then
        local index = self:GetDataIndex(self._posIndex)
        self._onItemCenter(self._dataList[index])
    end
end

function UILoopScroll:OnPosIndexChange()
    if self._onPosChange then
        local index = self:GetDataIndex(self._posIndex)
        self._onPosChange(index)
    end
end

function UILoopScroll:GetDataIndex(posIndex)
    local cnt = #self._dataList
    local step = nil
    if posIndex > 1 then
        step = 1 - posIndex + cnt
    else
        step = 1 - posIndex
    end
    local index = (1+step)%cnt
    if index == 0 then
        index = cnt
    end

    printInfoN(string.format("posIndex %s ,index %s",posIndex,index))
    return index
end


function UILoopScroll:Destroy()
    if self._seqCom then
        self._seqCom:Destroy()
    end
end

return UILoopScroll